package embedder

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
)

func TestOllamaBackendEmbed(t *testing.T) {
	dims := 768
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path != "/api/embed" {
			t.Errorf("unexpected path: %s", r.URL.Path)
		}
		if r.Method != http.MethodPost {
			t.Errorf("unexpected method: %s", r.Method)
		}

		var req ollamaEmbedRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			t.Fatalf("decode request: %v", err)
		}

		// Verify task prefix was prepended
		if len(req.Input) == 0 {
			t.Fatal("no input received")
		}

		embeddings := make([][]float64, len(req.Input))
		for i := range req.Input {
			vec := make([]float64, dims)
			for j := range vec {
				vec[j] = float64(j) * 0.001
			}
			embeddings[i] = vec
		}

		resp := ollamaEmbedResponse{Embeddings: embeddings}
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	cfg := config.EmbedderConfig{
		Backend:    "ollama",
		Model:      "test-model",
		Dimensions: dims,
		MaxTokens:  8192,
		Ollama:     config.OllamaConfig{Host: server.URL},
	}

	ob := NewOllamaBackendNoHealthCheck(cfg)

	ctx := context.Background()
	vec, err := ob.Embed(ctx, "test text", PurposeIndex)
	if err != nil {
		t.Fatalf("Embed: %v", err)
	}
	if len(vec) != dims {
		t.Errorf("vector length = %d, want %d", len(vec), dims)
	}
}

func TestOllamaBackendEmbedBatch(t *testing.T) {
	dims := 768
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req ollamaEmbedRequest
		json.NewDecoder(r.Body).Decode(&req)

		embeddings := make([][]float64, len(req.Input))
		for i := range req.Input {
			vec := make([]float64, dims)
			for j := range vec {
				vec[j] = float64(i)*0.1 + float64(j)*0.001
			}
			embeddings[i] = vec
		}

		resp := ollamaEmbedResponse{Embeddings: embeddings}
		json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	cfg := config.EmbedderConfig{
		Backend:    "ollama",
		Model:      "test-model",
		Dimensions: dims,
		Ollama:     config.OllamaConfig{Host: server.URL},
	}
	ob := NewOllamaBackendNoHealthCheck(cfg)

	vecs, err := ob.EmbedBatch(context.Background(), []string{"one", "two", "three"}, PurposeQuery)
	if err != nil {
		t.Fatalf("EmbedBatch: %v", err)
	}
	if len(vecs) != 3 {
		t.Fatalf("expected 3 vectors, got %d", len(vecs))
	}
	for i, vec := range vecs {
		if len(vec) != dims {
			t.Errorf("vector[%d] length = %d, want %d", i, len(vec), dims)
		}
	}
}

func TestOllamaBackendTaskPrefix(t *testing.T) {
	var receivedInputs []string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req ollamaEmbedRequest
		json.NewDecoder(r.Body).Decode(&req)
		receivedInputs = append(receivedInputs, req.Input...)

		embeddings := make([][]float64, len(req.Input))
		for i := range req.Input {
			embeddings[i] = make([]float64, 768)
		}
		json.NewEncoder(w).Encode(ollamaEmbedResponse{Embeddings: embeddings})
	}))
	defer server.Close()

	cfg := config.EmbedderConfig{
		Model:      "test",
		Dimensions: 768,
		Ollama:     config.OllamaConfig{Host: server.URL},
	}
	ob := NewOllamaBackendNoHealthCheck(cfg)

	ob.Embed(context.Background(), "hello", PurposeIndex)
	ob.Embed(context.Background(), "hello", PurposeQuery)

	if len(receivedInputs) < 2 {
		t.Fatal("expected at least 2 requests")
	}
	if receivedInputs[0] != "search_document: hello" {
		t.Errorf("index prefix: got %q", receivedInputs[0])
	}
	if receivedInputs[1] != "search_query: hello" {
		t.Errorf("query prefix: got %q", receivedInputs[1])
	}
}

func TestOllamaBackendDimensionMismatch(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req ollamaEmbedRequest
		json.NewDecoder(r.Body).Decode(&req)

		// Return wrong dimension
		embeddings := make([][]float64, len(req.Input))
		for i := range req.Input {
			embeddings[i] = make([]float64, 384) // Wrong!
		}
		json.NewEncoder(w).Encode(ollamaEmbedResponse{Embeddings: embeddings})
	}))
	defer server.Close()

	cfg := config.EmbedderConfig{
		Model:      "test",
		Dimensions: 768,
		Ollama:     config.OllamaConfig{Host: server.URL},
	}
	ob := NewOllamaBackendNoHealthCheck(cfg)

	_, err := ob.Embed(context.Background(), "test", PurposeQuery)
	if err == nil {
		t.Fatal("expected dimension mismatch error")
	}
}

func TestOllamaBackendServerError(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusInternalServerError)
		w.Write([]byte("model not found"))
	}))
	defer server.Close()

	cfg := config.EmbedderConfig{
		Model:      "test",
		Dimensions: 768,
		Ollama:     config.OllamaConfig{Host: server.URL},
	}
	ob := NewOllamaBackendNoHealthCheck(cfg)

	_, err := ob.Embed(context.Background(), "test", PurposeQuery)
	if err == nil {
		t.Fatal("expected error for 500 response")
	}
}
